// Tiny Express server with a deliberately small API surface.
const crypto = require('crypto');
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(
  express.json({
    verify: (req, _res, buffer) => {
      req.rawBody = buffer;
    },
  })
);

const webhookSecret = fs.readFileSync(path.join(__dirname, '..', 'data', 'webhook-secret.txt'), 'utf8').trim();
const acceptedEventIds = new Set();

const items = [
  { id: 1, name: 'alpha', qty: 3 },
  { id: 2, name: 'beta', qty: 5 },
];

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get('/items', (_req, res) => {
  res.json({ items });
});

app.get('/items/:id', (req, res) => {
  const id = Number(req.params.id);
  const item = items.find((it) => it.id === id);
  if (!item) {
    res.status(404).json({ error: 'not_found', id });
    return;
  }
  res.json({ item });
});

app.post('/webhook', (req, res) => {
  const signature = req.get('X-Signature');
  if (!req.rawBody || typeof signature !== 'string') {
    res.status(401).json({ error: 'invalid_signature' });
    return;
  }

  const expectedSignature = crypto.createHmac('sha256', webhookSecret).update(req.rawBody).digest();
  if (signature.length !== expectedSignature.length * 2 || !/^[a-f0-9]+$/.test(signature)) {
    res.status(401).json({ error: 'invalid_signature' });
    return;
  }

  const receivedSignature = Buffer.from(signature, 'hex');
  if (
    receivedSignature.length !== expectedSignature.length ||
    !crypto.timingSafeEqual(receivedSignature, expectedSignature)
  ) {
    res.status(401).json({ error: 'invalid_signature' });
    return;
  }

  const body = req.body;
  if (
    !body ||
    typeof body !== 'object' ||
    Array.isArray(body) ||
    typeof body.id !== 'string' ||
    body.id.length === 0 ||
    typeof body.type !== 'string' ||
    body.type.length === 0 ||
    typeof body.timestamp !== 'number' ||
    !body.data ||
    typeof body.data !== 'object' ||
    Array.isArray(body.data)
  ) {
    res.status(400).json({ error: 'invalid_body' });
    return;
  }

  if (acceptedEventIds.has(body.id)) {
    res.status(409).json({ error: 'duplicate_event', id: body.id });
    return;
  }

  acceptedEventIds.add(body.id);
  res.json({ accepted: true, id: body.id });
});

if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  app.listen(port, () => {
    console.log(`harbor-tools server listening on :${port}`);
  });
}

module.exports = { app };

