const { test } = require('node:test');
const assert = require('node:assert');
const crypto = require('node:crypto');
const fs = require('node:fs');
const http = require('node:http');
const path = require('node:path');
const { app } = require('../server');

const webhookSecret = fs.readFileSync(path.join(__dirname, '..', 'data', 'webhook-secret.txt'), 'utf8').trim();

function startServer() {
  return new Promise((resolve) => {
    const server = http.createServer(app);
    server.listen(0, () => resolve(server));
  });
}

function get(server, path) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    http
      .get(`http://127.0.0.1:${port}${path}`, (res) => {
        let body = '';
        res.on('data', (chunk) => (body += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
      })
      .on('error', reject);
  });
}

function post(server, path, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    const request = http.request(
      {
        host: '127.0.0.1',
        port,
        path,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          ...headers,
        },
      },
      (res) => {
        let responseBody = '';
        res.on('data', (chunk) => (responseBody += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(responseBody) }));
      }
    );
    request.on('error', reject);
    request.write(body);
    request.end();
  });
}

function sign(body) {
  return crypto.createHmac('sha256', webhookSecret).update(body).digest('hex');
}

test('GET /health returns ok', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/health');
    assert.strictEqual(status, 200);
    assert.deepStrictEqual(body, { status: 'ok' });
  } finally {
    server.close();
  }
});

test('GET /items returns list', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items');
    assert.strictEqual(status, 200);
    assert.ok(Array.isArray(body.items));
    assert.ok(body.items.length >= 2);
  } finally {
    server.close();
  }
});

test('GET /items/:id returns 404 for missing', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items/99999');
    assert.strictEqual(status, 404);
    assert.strictEqual(body.error, 'not_found');
  } finally {
    server.close();
  }
});

test('POST /webhook accepts a valid signed event', async () => {
  const server = await startServer();
  try {
    const event = { id: 'evt-test-happy', type: 'order.created', timestamp: 1700000000, data: { amount: 42 } };
    const body = JSON.stringify(event);
    const result = await post(server, '/webhook', body, { 'X-Signature': sign(body) });
    assert.strictEqual(result.status, 200);
    assert.deepStrictEqual(result.body, { accepted: true, id: event.id });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a replayed event id', async () => {
  const server = await startServer();
  try {
    const id = 'evt-test-replay';
    const firstBody = JSON.stringify({ id, type: 'order.created', timestamp: 1700000001, data: { amount: 10 } });
    const duplicateBody = JSON.stringify({ id, type: 'order.updated', timestamp: 1700000002, data: { amount: 20 } });

    const first = await post(server, '/webhook', firstBody, { 'X-Signature': sign(firstBody) });
    const duplicate = await post(server, '/webhook', duplicateBody, { 'X-Signature': sign(duplicateBody) });

    assert.strictEqual(first.status, 200);
    assert.strictEqual(duplicate.status, 409);
    assert.deepStrictEqual(duplicate.body, { error: 'duplicate_event', id });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a body tampered after signing', async () => {
  const server = await startServer();
  try {
    const originalBody = JSON.stringify({
      id: 'evt-test-tampered',
      type: 'order.created',
      timestamp: 1700000003,
      data: { amount: 42 },
    });
    const tamperedBody = JSON.stringify({
      id: 'evt-test-tampered',
      type: 'order.created',
      timestamp: 1700000003,
      data: { amount: 999 },
    });
    const result = await post(server, '/webhook', tamperedBody, { 'X-Signature': sign(originalBody) });
    assert.strictEqual(result.status, 401);
    assert.deepStrictEqual(result.body, { error: 'invalid_signature' });
  } finally {
    server.close();
  }
});

